{
  "sentences": [
    {
      "text": "請你走進來。",
      "pinyin": "Qǐng nǐ zǒu jìnlái.",
      "pinyin_numeric": "qing3 ni3 zou3 jin4lai2",
      "translation_en": "Please walk in.",
      "translation_ko": "안으로 걸어 들어오세요."
    },
    {
      "text": "他跑出去了。",
      "pinyin": "Tā pǎo chūqù le.",
      "pinyin_numeric": "ta1 pao3 chu1qu4 le0",
      "translation_en": "He ran out.",
      "translation_ko": "그가 밖으로 뛰어나갔어요."
    },
    {
      "text": "我們把書拿出來。",
      "pinyin": "Wǒmen bǎ shū ná chūlái.",
      "pinyin_numeric": "wo3men ba3 shu1 na2 chu1lai2",
      "translation_en": "We take the book out.",
      "translation_ko": "우리가 책을 꺼내요."
    },
    {
      "text": "貓從窗戶跳下來。",
      "pinyin": "Māo cóng chuānghu tiào xiàlái.",
      "pinyin_numeric": "mao1 cong2 chuang1hu tiao4 xia4lai2",
      "translation_en": "The cat jumped down from the window.",
      "translation_ko": "고양이가 창문에서 뛰어내려왔어요."
    },
    {
      "text": "請你帶咖啡上去。",
      "pinyin": "Qǐng nǐ dài kāfēi shàngqù.",
      "pinyin_numeric": "qing3 ni3 dai4 ka1fei1 shang4qu4",
      "translation_en": "Please bring the coffee up.",
      "translation_ko": "커피를 위로 가져가 주세요."
    },
    {
      "text": "他走進教室裡面。",
      "pinyin": "Tā zǒu jìn jiàoshì lǐmiàn.",
      "pinyin_numeric": "ta1 zou3 jin4 jiao4shi4 li3mian4",
      "translation_en": "He walked into the classroom.",
      "translation_ko": "그가 교실 안으로 걸어 들어갔어요."
    },
    {
      "text": "我們把東西放進去。",
      "pinyin": "Wǒmen bǎ dōngxī fàng jìnqù.",
      "pinyin_numeric": "wo3men ba3 dong1xi fang4 jin4qu4",
      "translation_en": "We put the things inside.",
      "translation_ko": "우리가 물건을 안에 넣었어요."
    },
    {
      "text": "弟弟從樓梯走下來。",
      "pinyin": "Dìdi cóng lóutī zǒu xiàlái.",
      "pinyin_numeric": "di4di cong2 lou2ti1 zou3 xia4lai2",
      "translation_en": "My younger brother walked down the stairs.",
      "translation_ko": "남동생이 계단에서 걸어 내려왔어요."
    },
    {
      "text": "請你幫我拿出去。",
      "pinyin": "Qǐng nǐ bāng wǒ ná chūqù.",
      "pinyin_numeric": "qing3 ni3 bang1 wo3 na2 chu1qu4",
      "translation_en": "Please help me take it out.",
      "translation_ko": "제가 밖으로 꺼내는 것을 도와주세요."
    },
    {
      "text": "他從公園跑回來。",
      "pinyin": "Tā cóng gōngyuán pǎo huílái.",
      "pinyin_numeric": "ta1 cong2 gong1yuan2 pao3 hui2lai2",
      "translation_en": "He ran back from the park.",
      "translation_ko": "그가 공원에서 뛰어 돌아왔어요."
    }
  ]
}
